function normalizeEnumValue(value: string) {
  return value.trim().toUpperCase()
}

function getFallbackStyleIndex(value: string) {
  let hash = 0

  for (const character of value) {
    hash = (hash * 31 + character.charCodeAt(0)) >>> 0
  }

  return hash % DATOOL_ENUM_BADGE_COLORS.length
}

function resolveConfiguredColor(
  value: string,
  colors?: DatoolEnumColorMap
): DatoolEnumBadgeColor | null {
  if (!colors) {
    return null
  }

  const normalizedValue = normalizeEnumValue(value)

  for (const [candidateValue, color] of Object.entries(colors)) {
    if (color && normalizeEnumValue(candidateValue) === normalizedValue) {
      return color
    }
  }

  return null
}

function resolveEnumBadgeStyle(
  value: string,
  options?: string[],
  colors?: DatoolEnumColorMap,
  variant: "default" | "outline" = "outline"
) {
  const normalizedValue = normalizeEnumValue(value)
  const configuredColor = resolveConfiguredColor(value, colors)

  const STYLES_LOOKUP =
    variant === "outline" ? ENUM_BADGE_OUTLINE_STYLES : ENUM_BADGE_STYLES

  if (configuredColor) {
    return STYLES_LOOKUP[configuredColor]
  }

  const optionIndex =
    options?.findIndex(
      (option) => normalizeEnumValue(option) === normalizedValue
    ) ?? -1

  if (optionIndex >= 0) {
    return STYLES_LOOKUP[
      DATOOL_ENUM_BADGE_COLORS[optionIndex % DATOOL_ENUM_BADGE_COLORS.length]
    ]
  }

  return STYLES_LOOKUP[
    DATOOL_ENUM_BADGE_COLORS[getFallbackStyleIndex(normalizedValue)]
  ]
}

export function EnumBadge({
  className,
  colors,
  options,
  value,
  variant = "default",
}: {
  className?: string
  colors?: DatoolEnumColorMap
  options?: string[]
  value: string
  variant?: "default" | "outline"
}) {
  return (
    <span
      className={cn(
        "rounded-md px-2 py-1 text-sm font-medium inline-flex max-w-full items-center leading-none whitespace-nowrap shadow-[0_1px_2px_rgba(15,23,42,0.04)] dark:shadow-none",
        resolveEnumBadgeStyle(value, options, colors, variant),
        className
      )}
      title={value}
    >
      <span className="truncate">{value}</span>
    </span>
  )
}

export type DataTableSearchFieldKind =
  | "date"
  | "enum"
  | "json"
  | "number"
  | "text"

export type DataTableSearchField<Row> = {
  getValue: (row: Row) => unknown
  id: string
  kind: DataTableSearchFieldKind
  options?: string[]
  sample?: string
}

export type DataTableSearchFieldSpec = Omit<
  DataTableSearchField<unknown>,
  "getValue"
>

export type DataTableSearchSuggestion = {
  group: "filters" | "input" | "values"
  id: string
  insertText: string
  keepOpen?: boolean
  label: string
  mode: "append" | "replace-token" | "replace-whole"
}

export type DataTableSearchFilterClause = {
  operator: ":" | "<" | ">"
  value: string
}

export type DataTableSearchTokenOperator = ":" | "." | "<" | ">"

export type DataTableSearchSelectorRange = {
  end: number
  fieldId: string
  operator: DataTableSearchTokenOperator
  start: number
  token: string
}

type DataTableSearchTokenRange = {
  end: number
  start: number
  token: string
}

function withSuggestionMode(
  suggestion: DataTableSearchSuggestion,
  mode: DataTableSearchSuggestion["mode"]
): DataTableSearchSuggestion {
  return {
    ...suggestion,
    mode,
  }
}

type TokenContext<Row> = {
  end: number
  field?: DataTableSearchField<Row>
  fragment: string
  operator?: DataTableSearchTokenOperator
  start: number
  token: string
}

type MatchedSearchToken<Row> = {
  field?: DataTableSearchField<Row>
  fieldId: string
  fragment: string
  operator: DataTableSearchTokenOperator
}

function matchSearchToken<Row>(
  token: string,
  fields: DataTableSearchField<Row>[]
): MatchedSearchToken<Row> | null {
  const match = token.match(/^([a-zA-Z0-9_.-]+)(:|>|<|\.)(.*)$/)

  if (!match) {
    return null
  }

  const [, fieldId, operator, fragment] = match

  return {
    field: fields.find((item) => item.id === fieldId),
    fieldId,
    fragment,
    operator: operator as DataTableSearchTokenOperator,
  }
}

function isSupportedOperator<Row>(
  field: DataTableSearchField<Row>,
  operator: DataTableSearchTokenOperator
) {
  switch (field.kind) {
    case "date":
    case "number":
      return operator === ":" || operator === ">" || operator === "<"
    case "json":
      return operator === ":" || operator === "."
    default:
      return operator === ":"
  }
}

function stringifyValue(value: unknown): string {
  if (value === null || value === undefined) {
    return ""
  }

  if (value instanceof Date) {
    return value.toISOString()
  }

  if (typeof value === "object") {
    return JSON.stringify(value)
  }

  return String(value)
}

function getSearchTokenRanges(value: string) {
  const ranges: DataTableSearchTokenRange[] = []
  let tokenStart = -1
  let isQuoted = false
  let isEscaped = false

  for (let index = 0; index < value.length; index += 1) {
    const character = value[index]

    if (tokenStart === -1) {
      if (/\s/.test(character)) {
        continue
      }

      tokenStart = index
    }

    if (isEscaped) {
      isEscaped = false
      continue
    }

    if (character === "\\") {
      isEscaped = true
      continue
    }

    if (character === '"') {
      isQuoted = !isQuoted
      continue
    }

    if (!isQuoted && /\s/.test(character)) {
      ranges.push({
        end: index,
        start: tokenStart,
        token: value.slice(tokenStart, index),
      })
      tokenStart = -1
    }
  }

  if (tokenStart !== -1) {
    ranges.push({
      end: value.length,
      start: tokenStart,
      token: value.slice(tokenStart),
    })
  }

  return ranges
}

export function splitSearchQuery(value: string) {
  return getSearchTokenRanges(value).map((range) => range.token)
}

function unescapeSearchTokenValue(value: string) {
  return value.replace(/\\(["\\])/g, "$1")
}

function unquoteSearchTokenValue(value: string) {
  const trimmedValue = value.trim()

  if (
    trimmedValue.length >= 2 &&
    trimmedValue.startsWith('"') &&
    trimmedValue.endsWith('"')
  ) {
    return unescapeSearchTokenValue(trimmedValue.slice(1, -1))
  }

  return unescapeSearchTokenValue(trimmedValue)
}

export function quoteSearchTokenValue(value: string) {
  if (!value || /[\s"]/u.test(value)) {
    return `"${value.replace(/["\\]/g, "\\$&")}"`
  }

  return value
}

function parseDateOperand(value: string) {
  const normalized = value.trim().toLowerCase()

  if (!normalized) {
    return null
  }

  if (normalized === "today") {
    const now = new Date()

    return new Date(now.getFullYear(), now.getMonth(), now.getDate())
  }

  const relativeMatch = normalized.match(/^-(\d+)d$/)

  if (relativeMatch) {
    const days = Number(relativeMatch[1])

    return new Date(Date.now() - days * 24 * 60 * 60 * 1000)
  }

  const timestamp = Date.parse(value)

  if (Number.isNaN(timestamp)) {
    return null
  }

  return new Date(timestamp)
}

function sameCalendarDay(left: Date, right: Date) {
  return (
    left.getFullYear() === right.getFullYear() &&
    left.getMonth() === right.getMonth() &&
    left.getDate() === right.getDate()
  )
}

function matchFieldToken<Row>(
  row: Row,
  field: DataTableSearchField<Row>,
  operator: ":" | "<" | ">",
  rawValue: string
) {
  const fieldValue = field.getValue(row)
  const stringValue = stringifyValue(fieldValue)

  if (!rawValue.trim()) {
    return true
  }

  if (field.kind === "enum") {
    return stringValue.toLowerCase() === rawValue.trim().toLowerCase()
  }

  if (field.kind === "number") {
    const left = Number(fieldValue)
    const right = Number(rawValue)

    if (Number.isNaN(left) || Number.isNaN(right)) {
      return stringValue.toLowerCase().includes(rawValue.trim().toLowerCase())
    }

    if (operator === ">") {
      return left > right
    }

    if (operator === "<") {
      return left < right
    }

    return left === right
  }

  if (field.kind === "date") {
    const nestedOperatorMatch =
      operator === ":" ? rawValue.match(/^([<>])(.*)$/) : null
    const effectiveOperator = nestedOperatorMatch
      ? (nestedOperatorMatch[1] as "<" | ">")
      : operator
    const effectiveValue = nestedOperatorMatch
      ? nestedOperatorMatch[2]
      : rawValue
    const left = parseDateOperand(stringValue)
    const right = parseDateOperand(effectiveValue)

    if (!left || !right) {
      return stringValue.toLowerCase().includes(rawValue.trim().toLowerCase())
    }

    if (effectiveOperator === ">") {
      return left > right
    }

    if (effectiveOperator === "<") {
      return left < right
    }

    return sameCalendarDay(left, right)
  }

  return stringValue.toLowerCase().includes(rawValue.trim().toLowerCase())
}

export function matchesFieldClauses<Row>(
  row: Row,
  field: DataTableSearchField<Row>,
  clauses: DataTableSearchFilterClause[]
) {
  return clauses.every((clause) =>
    matchFieldToken(row, field, clause.operator, clause.value)
  )
}

function buildBaseSuggestions<Row>(fields: DataTableSearchField<Row>[]) {
  return fields.flatMap<DataTableSearchSuggestion>((field) => {
    switch (field.kind) {
      case "date":
        return [
          {
            id: `${field.id}-eq`,
            group: "filters",
            insertText: `${field.id}:`,
            keepOpen: true,
            label: `${field.id}:`,
            mode: "append",
          },
          {
            id: `${field.id}-gt`,
            group: "filters",
            insertText: `${field.id}>`,
            keepOpen: true,
            label: `${field.id}>`,
            mode: "append",
          },
          {
            id: `${field.id}-lt`,
            group: "filters",
            insertText: `${field.id}<`,
            keepOpen: true,
            label: `${field.id}<`,
            mode: "append",
          },
        ]
      case "number":
        return [
          {
            id: `${field.id}-eq`,
            group: "filters",
            insertText: `${field.id}:`,
            keepOpen: true,
            label: `${field.id}:`,
            mode: "append",
          },
          {
            id: `${field.id}-gt`,
            group: "filters",
            insertText: `${field.id}>`,
            keepOpen: true,
            label: `${field.id}>`,
            mode: "append",
          },
          {
            id: `${field.id}-lt`,
            group: "filters",
            insertText: `${field.id}<`,
            keepOpen: true,
            label: `${field.id}<`,
            mode: "append",
          },
        ]
      case "json":
        return [
          {
            id: `${field.id}-dot`,
            group: "filters",
            insertText: `${field.id}.`,
            keepOpen: true,
            label: `${field.id}.`,
            mode: "append",
          },
          {
            id: `${field.id}-eq`,
            group: "filters",
            insertText: `${field.id}:`,
            keepOpen: true,
            label: `${field.id}:`,
            mode: "append",
          },
        ]
      default:
        return [
          {
            id: `${field.id}-eq`,
            group: "filters",
            insertText: `${field.id}:`,
            keepOpen: true,
            label: `${field.id}:`,
            mode: "append",
          },
        ]
    }
  })
}

export function getTokenContext<Row>(
  value: string,
  cursor: number,
  fields: DataTableSearchField<Row>[]
): TokenContext<Row> {
  const tokenRange = getSearchTokenRanges(value).find(
    (range) => cursor >= range.start && cursor <= range.end
  )
  const start = tokenRange?.start ?? cursor
  const end = tokenRange?.end ?? cursor
  const token = tokenRange?.token ?? ""
  const match = matchSearchToken(token, fields)

  if (!match) {
    return {
      end,
      fragment: token,
      start,
      token,
    }
  }

  return {
    end,
    field: match.field,
    fragment: match.fragment,
    operator: match.operator,
    start,
    token,
  }
}

export function getSelectorHighlightRanges<Row>(
  value: string,
  fields: DataTableSearchField<Row>[]
) {
  const ranges: DataTableSearchSelectorRange[] = []

  for (const { end, start, token } of getSearchTokenRanges(value)) {
    const parsedToken = matchSearchToken(token, fields)

    if (!parsedToken?.field) {
      continue
    }

    if (!isSupportedOperator(parsedToken.field, parsedToken.operator)) {
      continue
    }

    ranges.push({
      end,
      fieldId: parsedToken.field.id,
      operator: parsedToken.operator,
      start,
      token,
    })
  }

  return ranges
}

export function getSearchSuggestions<Row>(
  value: string,
  cursor: number,
  fields: DataTableSearchField<Row>[]
) {
  const token = getTokenContext(value, cursor, fields)
  const hasTokenFragment = token.fragment.trim().length > 0
  const inputSuggestion = value
    ? [
        {
          group: "input" as const,
          id: "input-value",
          insertText: value,
          label: value,
          mode: "replace-whole" as const,
        },
      ]
    : []

  if (!token.field || !token.operator) {
    const baseSuggestions = buildBaseSuggestions(fields)
    const filteredSuggestions = !token.fragment.trim()
      ? baseSuggestions
      : baseSuggestions.filter((suggestion) =>
          suggestion.label
            .toLowerCase()
            .includes(token.fragment.trim().toLowerCase())
        )

    if (hasTokenFragment) {
      return [
        ...inputSuggestion,
        ...filteredSuggestions.map((suggestion) =>
          withSuggestionMode(suggestion, "replace-token")
        ),
      ]
    }

    return [...inputSuggestion, ...filteredSuggestions]
  }

  if (token.field.kind === "enum" && token.operator === ":") {
    const selectedValue = unquoteSearchTokenValue(token.fragment).toLowerCase()

    if (
      selectedValue &&
      (token.field.options ?? []).some(
        (option) => option.toLowerCase() === selectedValue
      )
    ) {
      return inputSuggestion
    }

    const valueSuggestions = (token.field.options ?? [])
      .filter((option) => option.toLowerCase().includes(selectedValue))
      .map<DataTableSearchSuggestion>((option) => ({
        group: "values",
        id: `${token.field?.id}-${option}`,
        insertText: `${token.field?.id}:${quoteSearchTokenValue(option)}`,
        label: option,
        mode: "replace-token",
      }))

    return [...inputSuggestion, ...valueSuggestions]
  }

  if (token.field.kind === "date") {
    const sample = token.field.sample ?? new Date().toISOString()
    const suggestions = [
      {
        group: "values" as const,
        id: `${token.field.id}-today`,
        insertText: `${token.field.id}${token.operator}today`,
        label: "today",
        mode: "replace-token" as const,
      },
      {
        group: "values" as const,
        id: `${token.field.id}-7d`,
        insertText: `${token.field.id}${token.operator}-7d`,
        label: "-7d",
        mode: "replace-token" as const,
      },
      {
        group: "values" as const,
        id: `${token.field.id}-sample`,
        insertText: `${token.field.id}${token.operator}${sample}`,
        label: sample,
        mode: "replace-token" as const,
      },
    ]

    if (token.operator === ":") {
      suggestions[1] = {
        group: "values",
        id: `${token.field.id}-7d`,
        insertText: `${token.field.id}:>-7d`,
        label: ">-7d",
        mode: "replace-token",
      }
      suggestions[2] = {
        group: "values",
        id: `${token.field.id}-sample`,
        insertText: `${token.field.id}:>${sample}`,
        label: `>${sample}`,
        mode: "replace-token",
      }
    }

    const filteredSuggestions = !token.fragment.trim()
      ? suggestions
      : suggestions.filter((suggestion) =>
          suggestion.label
            .toLowerCase()
            .includes(token.fragment.trim().toLowerCase())
        )

    return [...inputSuggestion, ...filteredSuggestions]
  }

  const filteredSuggestions = buildBaseSuggestions([token.field]).filter(
    (suggestion) =>
      suggestion.label.toLowerCase().includes(token.token.trim().toLowerCase())
  )

  return [...inputSuggestion, ...filteredSuggestions]
}

export function applySuggestionToValue<Row>(
  value: string,
  cursor: number,
  fields: DataTableSearchField<Row>[],
  suggestion: DataTableSearchSuggestion
) {
  const token = getTokenContext(value, cursor, fields)
  const nextValue =
    suggestion.mode === "replace-whole"
      ? suggestion.insertText
      : suggestion.mode === "append"
        ? `${value.trimEnd()}${value.trim() ? " " : ""}${suggestion.insertText}`
        : `${value.slice(0, token.start)}${suggestion.insertText}${value.slice(token.end)}`
  const nextCursor =
    suggestion.mode === "append"
      ? nextValue.length
      : suggestion.mode === "replace-whole"
        ? suggestion.insertText.length
        : token.start + suggestion.insertText.length

  return {
    keepOpen: Boolean(suggestion.keepOpen),
    value: nextValue,
    selectionStart: nextCursor,
  }
}

export function parseSearchQuery<Row>(
  query: string,
  fields: DataTableSearchField<Row>[]
) {
  const trimmedQuery = query.trim()

  if (!trimmedQuery) {
    return {
      columnFilters: [] as Array<{
        id: string
        value: DataTableSearchFilterClause[]
      }>,
      globalFilter: "",
    }
  }

  const tokens = splitSearchQuery(trimmedQuery)
  const columnFiltersMap = new Map<string, DataTableSearchFilterClause[]>()
  const globalTokens: string[] = []

  tokens.forEach((token) => {
    const match = token.match(/^([a-zA-Z0-9_.-]+)(:|>|<)(.*)$/)

    if (!match) {
      globalTokens.push(token)
      return
    }

    const [, fieldId, operator, rawValue] = match
    const field = fields.find((item) => item.id === fieldId)

    if (!field) {
      globalTokens.push(token)
      return
    }

    const existingClauses = columnFiltersMap.get(field.id) ?? []

    existingClauses.push({
      operator: operator as ":" | "<" | ">",
      value: unquoteSearchTokenValue(rawValue),
    })

    columnFiltersMap.set(field.id, existingClauses)
  })

  return {
    columnFilters: Array.from(columnFiltersMap.entries()).map(
      ([id, value]) => ({
        id,
        value,
      })
    ),
    globalFilter: globalTokens.join(" "),
  }
}

export function matchesSearch<Row>(
  row: Row,
  query: string,
  fields: DataTableSearchField<Row>[]
) {
  const parsedQuery = parseSearchQuery(query, fields)
  const fallbackValue = fields
    .map((field) => stringifyValue(field.getValue(row)).toLowerCase())
    .join("\n")

  const matchesGlobalFilter = parsedQuery.globalFilter
    ? parsedQuery.globalFilter
        .split(/\s+/)
        .filter(Boolean)
        .every((token) => fallbackValue.includes(token.toLowerCase()))
    : true

  if (!matchesGlobalFilter) {
    return false
  }

  return parsedQuery.columnFilters.every((columnFilter) => {
    const field = fields.find((item) => item.id === columnFilter.id)

    if (!field) {
      return true
    }

    return matchesFieldClauses(row, field, columnFilter.value)
  })
}

export function getColumnHighlightTerms<Row>(
  query: string,
  columnId: string,
  fields: DataTableSearchField<Row>[]
) {
  const parsedQuery = parseSearchQuery(query, fields)
  const field = fields.find((item) => item.id === columnId)
  const globalTerms = parsedQuery.globalFilter.split(/\s+/).filter(Boolean)

  if (!field || field.kind !== "text") {
    return globalTerms
  }

  const columnTerms =
    parsedQuery.columnFilters
      .find((columnFilter) => columnFilter.id === columnId)
      ?.value.filter((clause) => clause.operator === ":" && clause.value.trim())
      .map((clause) => clause.value.trim()) ?? []

  return [...globalTerms, ...columnTerms]
}

export function buildEnumOptions<Row>(
  rows: Row[],
  getValue: (row: Row) => unknown
) {
  return Array.from(
    new Set(
      rows
        .map((row) => stringifyValue(getValue(row)).trim())
        .filter(Boolean)
    )
  )
}

import type { FilterFn } from "@tanstack/react-table"

import type { DataTableColumnConfig } from "../types"
import {
  buildEnumOptions,
  matchesFieldClauses,
  type DataTableSearchField,
  type DataTableSearchFieldKind,
  type DataTableSearchFilterClause,
} from "./data-table-text-search"

type TableRow = Record<string, unknown>

export type BuildTableSearchFieldsOptions = {
  fieldOptions?: Partial<Record<string, string[]>>
}

function stringifySampleValue(value: unknown) {
  if (value === null || value === undefined) {
    return undefined
  }

  if (value instanceof Date) {
    return value.toISOString()
  }

  if (typeof value === "object") {
    return JSON.stringify(value)
  }

  return String(value)
}

function getColumnValueGetter<TData extends TableRow>(
  column: DataTableColumnConfig<TData>
) {
  return (row: TData) => {
    if (column.accessorFn) {
      return column.accessorFn(row)
    }

    if (column.accessorKey) {
      return row[column.accessorKey]
    }

    return undefined
  }
}

function getDefaultFieldKind<TData extends TableRow>(
  column: DataTableColumnConfig<TData>
): DataTableSearchFieldKind {
  switch (column.kind) {
    case "date":
      return "date"
    case "enum":
      return "enum"
    case "json":
      return "json"
    case "number":
      return "number"
    default:
      return "text"
  }
}

export function resolveTableColumnId<TData extends TableRow>(
  column: DataTableColumnConfig<TData>,
  index: number
) {
  return (
    column.id ??
    column.accessorKey ??
    (column.header
      ? column.header.toLowerCase().replace(/\s+/g, "-")
      : `column-${index}`)
  )
}

export function buildTableSearchFields<TData extends TableRow>(
  columns: DataTableColumnConfig<TData>[],
  rows: TData[],
  options: BuildTableSearchFieldsOptions = {}
) {
  const latestRow = rows.at(-1)

  return columns.map<DataTableSearchField<TData>>((column, index) => {
    const columnId = resolveTableColumnId(column, index)
    const getValue = getColumnValueGetter(column)
    const kind = getDefaultFieldKind(column)

    if (kind === "enum") {
      return {
        getValue,
        id: columnId,
        kind,
        options:
          column.enumOptions ??
          options.fieldOptions?.[columnId] ??
          buildEnumOptions(rows, getValue),
      }
    }

    if (kind === "date") {
      const sampleValue = latestRow ? stringifySampleValue(getValue(latestRow)) : undefined

      return {
        getValue,
        id: columnId,
        kind,
        sample: sampleValue,
      }
    }

    return {
      getValue,
      id: columnId,
      kind,
    }
  })
}

export function withColumnSearchFilters<TData extends TableRow>(
  columns: DataTableColumnConfig<TData>[],
  fields: DataTableSearchField<TData>[]
) {
  const fieldMap = new Map(fields.map((field) => [field.id, field]))

  return columns.map((column, index) => {
    const columnId = resolveTableColumnId(column, index)
    const field = fieldMap.get(columnId)

    if (!field || column.filterFn) {
      return column
    }

    return {
      ...column,
      filterFn: ((row, _columnId, filterValue) => {
        const clauses = Array.isArray(filterValue)
          ? (filterValue as DataTableSearchFilterClause[])
          : []

        return matchesFieldClauses(row.original, field, clauses)
      }) as FilterFn<TData>,
    } satisfies DataTableColumnConfig<TData>
  })
}

export type SearchStatePersistence = "localStorage" | "url"

function getSearchLocalStorageKey(tableId: string) {
  return `${tableId}:search`
}

function getSearchUrlParam(tableId: string) {
  return `${tableId}-search`
}

function getTableUrlParam(tableId: string) {
  return `datatable-${tableId}`
}

export function hasSearchUrlPersistence(tableId: string) {
  if (typeof window === "undefined") {
    return false
  }

  const params = new URL(window.location.href).searchParams

  return (
    params.has(getSearchUrlParam(tableId)) ||
    params.has(getTableUrlParam(tableId))
  )
}

export function getInitialSearchPersistence(
  tableId: string
): SearchStatePersistence {
  return hasSearchUrlPersistence(tableId) ? "url" : "localStorage"
}

export function readPersistedSearch(
  tableId: string,
  statePersistence: SearchStatePersistence
) {
  if (typeof window === "undefined") {
    return ""
  }

  if (statePersistence === "url") {
    return (
      new URL(window.location.href).searchParams.get(
        getSearchUrlParam(tableId)
      ) ?? ""
    )
  }

  return window.localStorage.getItem(getSearchLocalStorageKey(tableId)) ?? ""
}

export function writePersistedSearch(
  tableId: string,
  statePersistence: SearchStatePersistence,
  value: string
) {
  if (typeof window === "undefined") {
    return
  }

  if (statePersistence === "url") {
    const url = new URL(window.location.href)

    if (value.trim()) {
      url.searchParams.set(getSearchUrlParam(tableId), value)
    } else {
      url.searchParams.delete(getSearchUrlParam(tableId))
    }

    window.history.replaceState(window.history.state, "", url)
    return
  }

  if (value) {
    window.localStorage.setItem(getSearchLocalStorageKey(tableId), value)
    return
  }

  window.localStorage.removeItem(getSearchLocalStorageKey(tableId))
}

export function clearUrlSearchPersistence(tableId: string) {
  if (typeof window === "undefined") {
    return
  }

  const url = new URL(window.location.href)

  url.searchParams.delete(getSearchUrlParam(tableId))
  url.searchParams.delete(getTableUrlParam(tableId))

  window.history.replaceState(window.history.state, "", url)
}

const durationFormatter = new Intl.NumberFormat(undefined, {
  maximumFractionDigits: 2,
})

const MS_IN_SECOND = 1000
const MS_IN_MINUTE = 60 * MS_IN_SECOND
const MS_IN_HOUR = 60 * MS_IN_MINUTE
const MS_IN_DAY = 24 * MS_IN_HOUR

export function formatDuration(ms: number, compact = false): string {
  if (ms === 0) {
    return "0"
  }

  if (ms < MS_IN_SECOND) {
    return `${durationFormatter.format(ms)}ms`
  }

  if (ms < MS_IN_MINUTE) {
    return `${durationFormatter.format(ms / MS_IN_SECOND)}s`
  }

  if (compact) {
    if (ms < MS_IN_HOUR) {
      return `${durationFormatter.format(ms / MS_IN_MINUTE)}m`
    }

    return `${durationFormatter.format(ms / MS_IN_HOUR)}h`
  }

  const days = Math.floor(ms / MS_IN_DAY)
  const hours = Math.floor((ms % MS_IN_DAY) / MS_IN_HOUR)
  const minutes = Math.floor((ms % MS_IN_HOUR) / MS_IN_MINUTE)
  const seconds = Math.floor((ms % MS_IN_MINUTE) / MS_IN_SECOND)
  const parts: string[] = []

  if (days > 0) {
    parts.push(`${days}d`)
  }

  if (hours > 0) {
    parts.push(`${hours}h`)
  }

  if (minutes > 0) {
    parts.push(`${minutes}m`)
  }

  if (hours <= 1 && (seconds > 0 || parts.length === 0)) {
    parts.push(`${seconds}s`)
  }

  return parts.join(" ")
}

import { format as formatDateFns, formatDistanceToNow } from "date-fns"

import type { DatoolDateFormat, DatoolRelativeDateFormat } from "../types"

const DEFAULT_INTL_DATE_FORMAT = {
  dateStyle: "medium",
} satisfies Intl.DateTimeFormatOptions

export function isRelativeDateFormat(
  value: DatoolDateFormat | unknown
): value is DatoolRelativeDateFormat {
  return (
    value != null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    "relative" in value &&
    (value as DatoolRelativeDateFormat).relative === true
  )
}

export function isIntlDateFormat(
  value: DatoolDateFormat | unknown
): value is Intl.DateTimeFormatOptions {
  return (
    Boolean(value) &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    !isRelativeDateFormat(value)
  )
}

export function normalizeDateFormatPattern(pattern: string) {
  return pattern
    .replace(/YYYY/g, "yyyy")
    .replace(/YY/g, "yy")
    .replace(/DD/g, "dd")
    .replace(/\bA\b/g, "a")
    .replace(/(H{1,2}|h{1,2}):MM(?=(:SS\b|:ss\b|:S\b|:s\b|\b))/g, "$1:mm")
    .replace(/:SS\b/g, ":ss")
    .replace(/:S\b/g, ":s")
}

export function parseDateValue(value: string | number | Date) {
  const date = value instanceof Date ? value : new Date(value)

  if (Number.isNaN(date.getTime())) {
    return null
  }

  return date
}

export function assertDateFormatShape(value: unknown) {
  if (value === undefined) {
    return
  }

  if (typeof value === "string") {
    try {
      formatDateFns(new Date(0), normalizeDateFormatPattern(value))
    } catch {
      throw new Error("The datool source config defines an invalid dateFormat.")
    }

    return
  }

  if (isRelativeDateFormat(value)) {
    return
  }

  if (!isIntlDateFormat(value)) {
    throw new Error(
      "The datool source config dateFormat must be a string, an object, or { relative: true }."
    )
  }

  try {
    new Intl.DateTimeFormat(undefined, value)
  } catch {
    throw new Error("The datool source config defines an invalid dateFormat.")
  }
}

export function formatDateValue(
  value: string | number | Date,
  dateFormat?: DatoolDateFormat
) {
  const date = parseDateValue(value)

  if (!date) {
    return String(value)
  }

  if (isRelativeDateFormat(dateFormat)) {
    return formatDistanceToNow(date, {
      addSuffix: dateFormat.addSuffix ?? false,
    })
  }

  if (typeof dateFormat === "string") {
    try {
      return formatDateFns(date, normalizeDateFormatPattern(dateFormat))
    } catch {
      return new Intl.DateTimeFormat(
        undefined,
        DEFAULT_INTL_DATE_FORMAT
      ).format(date)
    }
  }

  return new Intl.DateTimeFormat(
    undefined,
    dateFormat ?? DEFAULT_INTL_DATE_FORMAT
  ).format(date)
}

export function formatUtcDateValue(value: string | number | Date) {
  const date = parseDateValue(value)

  if (!date) {
    return String(value)
  }

  return date.toISOString()
}
